                switch (status) {
                    case WBPopupShowStatusShow:
                        // 正常展示弹窗
                        [self handleRichMessages:richMessagesData];
                        break;
                    case WBPopupShowStatusNotShow:
                        // 不展示弹窗，直接跳过
