        [WBNetworkManager.defaultManager sendNoticeEvent:self.popupStyle richMessageLinkId:self.mainImageRichMessageLinkId popupName:self.richMessageNoticeName eventName:self.mainImageRichMessageLinkLabel];
    } else {
        if (index < self.buttonData.count) {
            NSDictionary *data = self.buttonData[index];
            [WBNetworkManager.defaultManager sendNoticeEvent:self.popupStyle richMessageLinkId:data[@"id"] popupName:self.richMessageNoticeName eventName:data[@"label"]];
