}


- (void)showCustomPopupWithUserInfo:(NSDictionary *)popupInfo {
    NSString *imageUrlString = popupInfo[@"rich_message"][@"image"];
    NSURL *imageUrl = [NSURL URLWithString:imageUrlString];
    NSString *linkURL = popupInfo[@"rich_message"][@"links"][0][@"link"];    // 活动弹窗跳转链接（links数组的第一个link）
    NSString *richMessageLinkId = [popupInfo[@"rich_message"][@"links"][0][@"id"] stringValue];
    NSString *linkType = popupInfo[@"rich_message"][@"links"][0][@"type"];
    NSString *dismiss = popupInfo[@"rich_message"][@"links"][0][@"dismiss"];

    // 通过数组切片剔除第一个元素
    NSArray *links = popupInfo[@"rich_message"][@"links"];
    self.buttonData = [links subarrayWithRange:NSMakeRange(1, links.count - 1)]; // 从第二个元素开始

    self.popupStyle = (WBNoticeStyle)[popupInfo[@"rich_message"][@"style"] integerValue];
    self.mainImageRichMessageLinkId = popupInfo[@"rich_message"][@"links"][0][@"id"];
    self.richMessageNoticeName = popupInfo[@"rich_message"][@"name"];
    self.mainImageRichMessageLinkLabel = popupInfo[@"rich_message"][@"links"][0][@"label"];

    // 异步加载图片，避免阻塞主线程
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        NSData *imageData = [NSData dataWithContentsOfURL:imageUrl];
        UIImage *image = [UIImage imageWithData:imageData];

        // 回到主线程更新UI
        dispatch_async(dispatch_get_main_queue(), ^{
            WBVAppModel *runningVApp = [WBVAppManager sharedManager].runningVApp;
            if(!runningVApp) {
                CustomPopupViewController *customPopupVC = [[CustomPopupViewController alloc] initWithImageName:image linkURL:linkURL richMessageLinkId:richMessageLinkId linkType:linkType dismiss:dismiss buttonData:self.buttonData];
                customPopupVC.delegate = self;    // 设置 delegate
                customPopupVC.modalPresentationStyle = UIModalPresentationOverFullScreen;
                customPopupVC.transitioningDelegate = customPopupVC;

                UIViewController *currentViewController = [WBAppManager getUIApplicationRootViewController];
                // 循环查找，尝试找到当前展示的视图控制器
                while (currentViewController.presentedViewController != nil) {
                    currentViewController = currentViewController.presentedViewController;
                }
                // 检查视图是否已经加入窗口层级
                if (!currentViewController.view.window) {
                    // 如果没有找到当前模态视图控制器，则退回到使用 WBAppManager 的根视图控制器
                    currentViewController = [WBAppManager getUIApplicationRootViewController];
                    if (!currentViewController.view.window) {
                        // 若根视图控制器不在窗口视图中，打印错误信息并终止方法的执行
                        NSLog(@"Error: Neither the current nor the root view controller's views are in the window hierarchy. Cannot present CustomPopupViewController.");
                        return;
                    }
                }
                [currentViewController presentViewController:customPopupVC animated:YES completion:nil];    // 展示活动弹窗
                if([popupInfo[@"rich_message"] objectForKey:@"popupId"]) {
                    NSInteger popupId = [popupInfo[@"rich_message"][@"popupId"] intValue];
                    [WBNetworkManager.defaultManager sendPopupId:popupId];  // 上报图片弹窗已展示
