- (BOOL)isValidInternationalEmail:(NSString *)email {
    if (email.length == 0 || email.length > 254) {
        return NO;
    }

    // 国际化邮箱正则表达式
    NSString *emailRegex =
        @"^(?:[\\p{L}0-9!#$%&'*+/=?^_`{|}~-]+(?:\\.[\\p{L}0-9!#$%&'*+/=?^_`{|}~-]+)*|\"(?:[\\x01-\\x08\\x0b\\x0c\\x0e-\\x1f\\x21\\x23-\\x5b\\x5d-\\x7f]|\\\\[\\x01-\\x09\\x0b\\x0c\\x0e-\\x7f])*\")@"
        "(?:(?:[\\p{L}0-9](?:[\\p{L}0-9-]*[\\p{L}0-9])?\\.)+[\\p{L}0-9](?:[\\p{L}0-9-]*[\\p{L}0-9])?|"
        @"\\[(?:(?:(2(5[0-5]|[0-4][0-9])|1[0-9][0-9]|[1-9]?[0-9]))\\.){3}(?:(2(5[0-5]|[0-4][0-9])|1[0-9][0-9]|[1-9]?[0-9])|[\\p{L}0-9-]*[\\p{L}0-9]:(?:[\\x01-\\x08\\x0b\\x0c\\x0e-\\x1f\\x21-\\x5a\\x53-\\x7f]|\\\\[\\x01-\\x09\\x0b\\x0c\\x0e-\\x7f])+)\\])$";

    NSPredicate *emailTest = [NSPredicate predicateWithFormat:@"SELF MATCHES %@", emailRegex];

    // 拆分检查域名部分
    NSRange atRange = [email rangeOfString:@"@"];
    if (atRange.location == NSNotFound || atRange.location == 0 || atRange.location == email.length-1) {
        return NO;
    }

    NSString *domainPart = [email substringFromIndex:atRange.location+1];
    return [emailTest evaluateWithObject:email] && [self isValidDomain:domainPart];
}

- (BOOL)isValidDomain:(NSString *)domain {
    // 域名国际化验证 (支持IDN)
    NSString *domainRegex = @"^([\\p{L}0-9-]+\\.)+[\\p{L}0-9-]{2,}$";
    NSPredicate *domainTest = [NSPredicate predicateWithFormat:@"SELF MATCHES %@", domainRegex];
    return [domainTest evaluateWithObject:domain];
}


