    BOOL notFirst = [[NSUserDefaults standardUserDefaults] boolForKey:@"notFirstLaunch"];
    if (!notFirst) {
        [self showIntroMask];
    }
}

- (void)checkAndExecutePendingRoute {
    NSURL *pendingURL = WBReferralManager.sharedManager.pendingRouteURL;
    NSString *sourceInterface = WBReferralManager.sharedManager.pendingRouteSourceInterface;

    if (pendingURL) {
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [[WBRouteManager sharedManager] performRoute:pendingURL sourceInterface:sourceInterface];

            // Clear after execution
            WBReferralManager.sharedManager.pendingRouteURL = nil;
            WBReferralManager.sharedManager.pendingRouteSourceInterface = nil;
        });
    }
}

