- (void)loadResourcesFromUnzippedArchive:(NSString *)unzippedDirectory popupInfo:popupInfo {
    // 弹窗动画数据
    NSArray *filenames = @[@"A_main", @"B_main", @"A_sub", @"B_sub", @"frontAnimation", @"rearAnimation", @"handleAnimationAtEnd"];
    NSMutableDictionary<NSString *, NSString *> *jsonPaths = [NSMutableDictionary dictionary];

    if (![unzippedDirectory isEqualToString:@""]) {
        for (NSString *filename in filenames) {
            jsonPaths[filename] = [unzippedDirectory stringByAppendingPathComponent:[filename stringByAppendingString:@".json"]];
        }
    } else {    // 如果后端所传动画数据为空，则使用默认动画
        for (NSString *filename in filenames) {
            jsonPaths[filename] = [[NSBundle mainBundle] pathForResource:filename ofType:@"json"];
        }
    }

    NSMutableDictionary<NSString *, NSDictionary *> *jsonDictionaries = [NSMutableDictionary dictionary];
    NSError *error = nil;

    for (NSString *filename in filenames) {
        NSString *path = jsonPaths[filename];
        NSData *jsonData = [NSData dataWithContentsOfFile:path];
        if (jsonData) {
            id jsonObject = [NSJSONSerialization JSONObjectWithData:jsonData options:kNilOptions error:&error];
            if ([jsonObject isKindOfClass:[NSDictionary class]]) {
                jsonDictionaries[filename] = (NSDictionary *)jsonObject;
            } else if (error) {
                NSLog(@"Error parsing JSON file %@: %@", filename, error);
            } else {
                NSLog(@"Invalid JSON data in file %@", filename);
            }
        } else {
            NSLog(@"Failed to load %@ from %@", filename, path);
        }
    }

    NSDictionary *jsonDictAmain = jsonDictionaries[@"A_main"];
    NSDictionary *jsonDictBmain = jsonDictionaries[@"B_main"];
    NSDictionary *jsonDictAsub = jsonDictionaries[@"A_sub"];
    NSDictionary *jsonDictBsub = jsonDictionaries[@"B_sub"];
    NSDictionary *jsonDictFront = jsonDictionaries[@"frontAnimation"];
    NSDictionary *jsonDictRear = jsonDictionaries[@"rearAnimation"];
    NSDictionary *jsonDictAnimationEnd = jsonDictionaries[@"handleAnimationAtEnd"];

    // 弹窗其他数据
    NSString *linkURL = popupInfo[@"rich_message"][@"links"][0][@"link"];    // A视图的点击事件链接（links数组的第一个link）
    NSString *richMessageLinkId = [popupInfo[@"rich_message"][@"links"][0][@"id"] stringValue];
    NSString *linkType = popupInfo[@"rich_message"][@"links"][0][@"type"];    // 弹窗链接类型（links数组的第一个link）
    NSString *dismiss = popupInfo[@"rich_message"][@"links"][0][@"dismiss"];
    self.linkURL = linkURL;
    self.richMessageLinkId = richMessageLinkId;
    self.linkType = linkType;
    self.dismiss = dismiss;
    self.noticeStyle = (WBNoticeStyle)[popupInfo[@"rich_message"][@"style"] integerValue];
    self.noticeId = popupInfo[@"rich_message"][@"links"][0][@"id"];
    self.noticeName = popupInfo[@"rich_message"][@"name"];
    self.noticeLabel = popupInfo[@"rich_message"][@"links"][0][@"label"];

    dispatch_async(dispatch_get_main_queue(), ^{
        WBVAppModel *runningVApp = [WBVAppManager sharedManager].runningVApp;
        if(!runningVApp) {
            DynamicPopupViewController *dynamicPopupVC;

            if (!jsonDictFront && !jsonDictAmain) {    // 如果前置动画、A动画都不存在
                return;
            } else {
                if (self.linkURL && [self.linkURL isKindOfClass:[NSString class]]) {
                    // 初始化动态弹窗管理视图控制器
                    dynamicPopupVC = [[DynamicPopupViewController alloc] initWithAmain:jsonDictAmain Bmain:jsonDictBmain Asub:jsonDictAsub Bsub:jsonDictBsub frontAnimation:jsonDictFront rearAnimation:jsonDictRear linkUrl:self.linkURL richMessageLinkId:self.richMessageLinkId AnimationAtEnd:jsonDictAnimationEnd linkType:self.linkType dismiss:self.dismiss];
                } else {
                    NSLog(@"Invalid route link");
                    return;
                }
            }

            // 全屏、原生动画代理
            dynamicPopupVC.modalPresentationStyle = UIModalPresentationOverFullScreen;
            dynamicPopupVC.transitioningDelegate = dynamicPopupVC;


            UIViewController *currentViewController = [WBAppManager getUIApplicationRootViewController];

            // 循环查找，尝试找到当前展示的视图控制器
            while (currentViewController.presentedViewController != nil) {
                currentViewController = currentViewController.presentedViewController;
            }
            // 检查视图是否已经加入窗口层级
            if (!currentViewController.view.window) {
                // 如果没有找到当前模态视图控制器，则退回到使用 WBAppManager 的根视图控制器
                currentViewController = [WBAppManager getUIApplicationRootViewController];
                if (!currentViewController.view.window) {
                    // 若使用 WBAppManager 的根视图控制器不在窗口视图中，打印一条错误信息并终止方法的执行
                    NSLog(@"Error: Neither the current nor the root view controller's views are in the window hierarchy. Cannot present CustomPopupViewController.");
                    return;
                }
            }
            [currentViewController presentViewController:dynamicPopupVC animated:YES completion:nil];    // 展示动态活动弹窗
            if([popupInfo[@"rich_message"] objectForKey:@"popupId"]) {
                NSInteger popupId = [popupInfo[@"rich_message"][@"popupId"] intValue];
                [WBNetworkManager.defaultManager sendPopupId:popupId];  // 上报动画弹窗已展示
            } else if([popupInfo[@"rich_message"] objectForKey:@"scheduleId"]) {
                NSInteger scheduleId = [popupInfo[@"rich_message"][@"scheduleId"] intValue];
                [WBNetworkManager.defaultManager sendScheduleId:scheduleId];  // 上报优惠券动画弹窗已展示
            }
        }
    });
}

// 解压资源压缩包、加载资源、展示动态弹窗
- (void)presentPopupWithZipUrl:(NSString *)zipUrlString popupInfo:(NSDictionary *)popupInfo {
    // 使用带有回调的下载方法
    [self downloadZipFileWithURLString:zipUrlString completion:^(NSString *zipFilePath) {
        // 保存压缩包文件路径
        self.zipFilePath = zipFilePath;

        // 使用WBStorageManager中的tmpRoot来获取解压后的文件夹路径
        NSString *unzippedDirectory = [[WBStorageManager sharedManager].tmpRoot stringByAppendingPathComponent:@"UnzippedFiles"];

        // 保存解压文件路径
        self.unzippedFolderPath = unzippedDirectory;

        // 如果解压文件夹不存在，就进行创建
        if (![[NSFileManager defaultManager] fileExistsAtPath:unzippedDirectory isDirectory:nil]) {
            NSError *error;
            [[NSFileManager defaultManager] createDirectoryAtPath:unzippedDirectory withIntermediateDirectories:YES attributes:nil error:&error];
            if (error) {
                NSLog(@"Error creating directory: %@", error.localizedDescription);
            }
        }

        // 解压资源压缩包
        if ([self unzipArchiveWithPath:self.zipFilePath toDestination:unzippedDirectory]) {
            // 获取实际的解压路径
            NSArray *contents = [[NSFileManager defaultManager] contentsOfDirectoryAtPath:unzippedDirectory error:nil];
            NSString *actualUnzippedDirectory = nil;
            for (NSString *content in contents) {
                if (![content isEqualToString:@"."]) { // 排除当前目录 "."
                    actualUnzippedDirectory = [unzippedDirectory stringByAppendingPathComponent:content];
                    break;
                }
            }

            if (actualUnzippedDirectory) {
                // 在解压文件夹下加载资源
                [self loadResourcesFromUnzippedArchive:actualUnzippedDirectory popupInfo:popupInfo];
            } else {
                NSLog(@"Error actualUnzippedDirectory");
            }
        }
    }];
}

// 下载压缩包
- (void)downloadZipFileWithURLString:(NSString *)urlString completion:(void (^)(NSString *zipFilePath))completion {
    NSURL *zipUrl = [NSURL URLWithString:urlString];
    if (!zipUrl) {
        NSLog(@"Invalid URL provided.");
        return;
    }

    // 提取压缩包的名字
    NSString *originalFilename = [self extractOriginalFilenameFromURL:zipUrl];
    if (originalFilename == nil) {
        originalFilename = @"DynamicPopupZip.zip"; // 标准压缩包名
    }

    // 使用WBStorageManager中cacheRoot作为压缩包存储位置
    NSString *zipFilePath = [[WBStorageManager sharedManager].cacheRoot stringByAppendingPathComponent:originalFilename];

