- (void)performRoute:(NSURL *)url completion:(void (^ _Nullable)(id<JUNRouter> _Nonnull))completionHandler sourceInterface:(nullable NSString *)sourceInterface {
    [self logRouteEventWithURL:url sourceInterface:sourceInterface];
    if ([url.path isEqualToString:@"/action/popup"] && sourceInterface.length > 0) {
        NSURLComponents *components = [NSURLComponents componentsWithURL:url resolvingAgainstBaseURL:NO];
        NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new];
        NSURLQueryItem *sourceItem = [NSURLQueryItem queryItemWithName:@"sourceInterface" value:sourceInterface];
        [queryItems addObject:sourceItem];
        components.queryItems = queryItems;
        url = components.URL;
    }
    if ([url.path isEqualToString:@"/page/mine/CustomerServiceByWeChatSDK"]) {
        NSURLComponents *components = [NSURLComponents componentsWithURL:url resolvingAgainstBaseURL:NO];
        components.path = @"/action/CustomerServiceByWeChatSDK";
        url = components.URL;
    }
    if ([url.path isEqualToString:@"/page/mine/CustomerServiceByOldMethod"]) {
        NSURLComponents *components = [NSURLComponents componentsWithURL:url resolvingAgainstBaseURL:NO];
        components.path = @"/action/CustomerServiceByOldMethod";
        url = components.URL;
    }
    [self.routeExpress deliver:url toFirstRouter:self completion:completionHandler];
}这个方法是干嘛的

