                            UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
                            [rootVC presentViewController:webVC animated:true completion:nil];
                            if (link.isDismissOnTap) return;
                            webVC.dismissBlock = ^{
                                [rootVC presentViewController:self.presentedPopup animated:true completion:nil];
                            };
                        }];
                    }
                };
            }
            break;
        case WBRichMessageLinkTypeAppstoreRate:
            if (1) {
                block = ^{
                    [WBAppManager.sharedManager writeReviewInAppStore:@"popup"];
                };
            }
            break;
        case WBRichMessageLinkTypeDismiss:
            if (1) {
                block = ^{
                    @strongify(self)
                    [self dismissPopup];
                };
            }
            break;
        case WBRichMessageLinkTypeExit:
            if (1) {
                block = ^{
                    exit(0);
                };
            }
            break;
        case WBRichMessageLinkTypeDefault:
            if (self.stashedDefaultHandler) {
                block = self.stashedDefaultHandler;
                self.stashedDefaultHandler = nil;

            }
            break;
        default:
            if (link.generalAction) {
                block = link.generalAction;
            } else {
                NSLog(@"no action defined for operation:%@", link.label);
            }
            break;
    }
    return block;
}

@end
