#import "CustomPopupViewController.h"
#import "WBCustomPopupManager.h"
#import "CustomTransition.h" // 引入自定义转场动画类
#import "WBRouteManager.h"
#import "WBWebViewController.h"
#import "DynamicPopupViewController.h"
#import "WBWebViewManager.h"

@interface CustomPopupViewController ()

@property (strong, nonatomic) UIImageView *imageView;
@property (strong, nonatomic) UIImage *mainImage;
@property (strong, nonatomic) UIButton *closeButton;
@property (copy, nonatomic) NSArray *buttonData;
@property (strong, nonatomic) NSArray<UIButton *> *tapButtons;

@end

@implementation CustomPopupViewController

#pragma mark - Initialization

- (instancetype)initWithImageName:(UIImage *)image linkURL:(NSString *)linkURL richMessageLinkId:(NSString *)richMessageLinkId linkType:(NSString *)linkType dismiss:(NSString *)dismiss buttonData:buttonData{
    self = [super initWithNibName:nil bundle:nil];
    if (self) {
        self.mainImage = image;     // 弹窗主图
        self.linkURL = linkURL;     // 活动弹窗跳转链接
        self.richMessageLinkId = richMessageLinkId;
        self.linkType = linkType;   // 活动链接的跳转类型
        self.dismiss = dismiss;     // 活动弹窗是否关闭
        self.buttonData = buttonData;
        [self setupUI];
    }
    return self;
}


#pragma mark - View Lifecycle

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = [UIColor colorWithWhite:0 alpha:0.8]; // 透明黑色背景
}

#pragma mark - Setup UI

- (void)setupUI {
    [self generateTapButtons];   // 在添加视图之前生成按钮
    [self addSubviews];          // 添加所有子视图
    [self addAllConstraints];    // 添加约束
    [self addGestures];          // 添加手势
    [self setupCloseButton];     // 设置关闭按钮

    if (self.mainImage) {
        self.imageView.image = self.mainImage;
    }
}

- (void)addSubviews {
    [self.view addSubview:self.imageView];
    [self.view addSubview:self.closeButton];

    // 确保按钮已经被正确创建并添加到视图中
    for (UIButton *button in self.tapButtons) {
        [self.view addSubview:button];
    }

    // 调用布局方法来设置按钮位置
    [self layoutTapButtons];
}


- (void)addAllConstraints {
    CGFloat aspectRatio = self.mainImage.size.height / self.mainImage.size.width;
    [self.imageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.view);
        if (self.buttonData.count >= 1) {
            make.centerY.equalTo(self.view).offset(ZOOM(-30));
        } else {
            make.centerY.equalTo(self.view);
        }
        make.width.mas_equalTo(ZOOM(301));
        make.height.mas_equalTo(ZOOM(301) * aspectRatio);
    }];

    [self.closeButton mas_makeConstraints:^(MASConstraintMaker *make) {
        if ([WBAppManager sharedManager].isRTL) {
            make.left.equalTo(self.imageView.mas_left);
        } else {
            make.right.equalTo(self.imageView.mas_right);
        }
        make.top.equalTo(self.imageView.mas_top);
        make.width.height.mas_equalTo(ZOOM(24));
    }];

}

- (void)addGestures {
    UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(imageTapped:)];
    tapGesture.numberOfTapsRequired = 1;
    tapGesture.cancelsTouchesInView = NO;
    [self.imageView addGestureRecognizer:tapGesture];
    self.imageView.userInteractionEnabled = YES;
}

- (void)setupCloseButton {
    [self.closeButton setBackgroundImage:[UIImage imageNamed:@"Close_icon"] forState:UIControlStateNormal];
    [self.closeButton addTarget:self action:@selector(dismissPopup) forControlEvents:UIControlEventTouchUpInside];
}


#pragma mark - Actions

- (void)imageTapped:(UITapGestureRecognizer *)gestureRecognizer {
    [self handleTapEventForButtonAtIndex:-1];  // -1 用于表示图片点击
}

- (void)buttonClicked:(UIButton *)button {
    // 获取按钮的索引，统一处理点击事件
    NSInteger index = button.tag;
    [self handleTapEventForButtonAtIndex:index];  // 传递按钮的索引
}

- (void)handleTapEventForButtonAtIndex:(NSInteger)index {
    NSString *link = nil;
    NSString *linkType = nil;
    NSString *dismiss = nil;
    NSString *richMessageLinkId = nil;

    if (index == -1) {
        // 图片被点击，使用全局的 linkURL 和 linkType
        link = self.linkURL;
        richMessageLinkId = self.richMessageLinkId;
        linkType = self.linkType;
        dismiss = self.dismiss;
    } else {
        // 按钮被点击，使用该按钮的数据
        if (index < self.buttonData.count) {
            NSDictionary *data = self.buttonData[index];
            link = data[@"link"];
            richMessageLinkId = [data[@"id"] stringValue];
            linkType = data[@"type"];
            dismiss = data[@"dismiss"];
        }
    }

    [[WBCustomPopupManager sharedManager] sendClickEvent:index];    // 点击事件上报

    // 判断 link 是否有效
    if (link && ![link isEqualToString:@""]) {
        if ([linkType integerValue] == linkType_Dismiss || [linkType integerValue] == linkType_Default) {
            if ([linkType integerValue] == linkType_Default) {
                WBCustomPopupManager *manager = [WBCustomPopupManager sharedManager];
                if (manager.stashedDefaultHandler) {
                    manager.stashedDefaultHandler();
                    manager.stashedDefaultHandler = nil;
                }
            }
            [self dismissPopup];
            NSLog(@"回调路由无处理，关闭");
        } else if ([linkType integerValue] == linkType_UrlScheme) {
            [self dismissPopup];    // 先关闭弹窗
            __block NSURL *url = [NSURL URLWithString:link];
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                if ([link hasPrefix:@"webox:///action/promoReceive"]) {
                    [[NSNotificationCenter defaultCenter] postNotificationName:WBStaticPromoReceiveNotification object:nil];
                }

                NSString *triggerId = self.richMessageLinkId ?: nil;
                if ([url.absoluteString isEqualToString:@"webox:///page/vip"] && triggerId) {
                    NSURLComponents *components = [NSURLComponents componentsWithString:url.absoluteString];
                    NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new];
                    NSURLQueryItem *triggerItem = [NSURLQueryItem queryItemWithName:@"triggerId" value:triggerId];
                    [queryItems addObject:triggerItem];
                    components.queryItems = queryItems;
                    url = components.URL;
                }
                [[WBRouteManager sharedManager] performRoute:url sourceInterface:@"action/popup"];  // 路由跳转
            });
        } else if ([linkType integerValue] == linkType_Safari) {
            [UIApplication.sharedApplication openURL:[NSURL URLWithString:link] options:@{} completionHandler:nil]; // 浏览器跳转
            if ([dismiss integerValue]) {
                [self dismissPopup];
            }
        } else if ([linkType integerValue] == linkType_WebView) {
            WBWebViewManager *webVC = [[WBWebViewManager alloc] initWithURL:[NSURL URLWithString:link]];
            webVC.modalPresentationStyle = UIModalPresentationFullScreen;
            UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
            webVC.webVC.dismissBlock = ^{
                [rootVC dismissViewControllerAnimated:YES completion:nil];
            };
            [self dismissViewControllerAnimated:false completion:^{
                [rootVC presentViewController:webVC animated:true completion:nil];
                if (![dismiss integerValue]) {
                    webVC.webVC.dismissBlock = ^{
                        [rootVC presentViewController:self animated:true completion:nil];
                    };
                }
            }];
        } else {
            NSLog(@"这是一个暂时无法识别的link类型");
        }
    }
}

- (void)dismissPopup {
    [self.presentingViewController dismissViewControllerAnimated:YES completion:^{
        if (self.delegate) {
            [self.delegate customPopupDidDismiss];
        }
    }];
}

#pragma mark - Buttons

- (void)generateTapButtons {
    NSMutableArray<UIButton *> *buttons = [NSMutableArray array];
    for (NSDictionary *data in self.buttonData) {
        UIButton *button = [UIButton buttonWithType:UIButtonTypeCustom];
        NSString *buttonImageUrl = data[@"image"];
        NSURL *imageUrl = [NSURL URLWithString:buttonImageUrl];
        // 异步加载图片
        NSURLSession *session = [NSURLSession sharedSession];
        [[session dataTaskWithURL:imageUrl completionHandler:^(NSData * _Nullable data, NSURLResponse * _Nullable response, NSError * _Nullable error) {
            if (error) {
                NSLog(@"Failed to load image: %@", error.localizedDescription);
                return;
            }
            UIImage *image = [UIImage imageWithData:data];
            dispatch_async(dispatch_get_main_queue(), ^{
                // 在主线程中设置图片
                [button setBackgroundImage:image forState:UIControlStateNormal];
            });
        }] resume];
        NSInteger index = [buttons count];
        button.tag = index; // 使用 tag 来标识按钮
        [button addTarget:self action:@selector(buttonClicked:) forControlEvents:UIControlEventTouchUpInside];
        [buttons addObject:button];
    }
    self.tapButtons = [buttons copy];  // 保存所有生成的按钮
}


- (void)layoutTapButtons {
    CGFloat totalWidth = ZOOM(301);  // 总宽度
    NSInteger buttonCount = self.tapButtons.count;
    CGFloat buttonHeight = ZOOM(60);

    CGFloat buttonWidth = 0;
    CGFloat spacing = 0;

    // 根据按钮数量动态调整按钮宽度和间距
    switch (buttonCount) {
        case 1: {
            buttonWidth = ZOOM(184);
            spacing = 0;
            break;
        }
        case 2: {
            buttonWidth = ZOOM(124);
            spacing = ZOOM(33);
            break;
        }
        case 3: {
            buttonWidth = ZOOM(84);
            spacing = ZOOM(14);
            break;
        }
        case 4: {
            buttonWidth = ZOOM(64);
            spacing = ZOOM(8);
            break;
        }
        default: {
            buttonWidth = ZOOM(64);
            CGFloat totalButtonWidth = buttonWidth * buttonCount;
            CGFloat sidePadding = ZOOM(10);
            CGFloat remainingSpace = totalWidth - totalButtonWidth - 2 * sidePadding;
            spacing = MAX(remainingSpace / (buttonCount - 1), 0);
            break;
        }
    }

    // 创建一个父容器视图，用于包裹按钮组
    UIView *buttonContainerView = [[UIView alloc] init];
    [self.view addSubview:buttonContainerView];
    [buttonContainerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.imageView.mas_bottom);                 // 按钮距离图片的固定间距
        make.centerX.equalTo(self.imageView.mas_centerX);            // 水平居中对齐
        make.height.mas_equalTo(buttonHeight);                       // 高度固定为按钮高度
        make.width.mas_equalTo(totalWidth);                          // 容器宽度固定为设计宽度
    }];

    // 在容器内布局按钮
    BOOL isRTL = [WBAppManager sharedManager].isRTL;
    for (NSInteger i = 0; i < buttonCount; i++) {
        UIButton *button = self.tapButtons[i];
        [buttonContainerView addSubview:button];

        [button mas_makeConstraints:^(MASConstraintMaker *make) {
            make.width.mas_equalTo(buttonWidth);
            make.height.mas_equalTo(buttonHeight);
            make.centerY.equalTo(buttonContainerView);  // 垂直居中

            if (buttonCount == 1) {
                make.centerX.equalTo(buttonContainerView.mas_centerX);
            } else if (buttonCount == 2) {
                if (i == 0) {
                    if (isRTL) {
                        make.right.equalTo(buttonContainerView.mas_right).offset(ZOOM(-10));
                    } else {
                        make.left.equalTo(buttonContainerView.mas_left).offset(ZOOM(10));
                    }
                } else {
                    if (isRTL) {
                        make.right.equalTo(self.tapButtons[0].mas_left).offset(-spacing);
                    } else {
                        make.left.equalTo(self.tapButtons[0].mas_right).offset(spacing);
                    }
                }
            } else if (buttonCount == 3) {
                if (i == 0) {
                    if (isRTL) {
                        make.right.equalTo(buttonContainerView.mas_right).offset(ZOOM(-10));
                    } else {
                        make.left.equalTo(buttonContainerView.mas_left).offset(ZOOM(10));
                    }
                } else if (i == 1) {
                    if (isRTL) {
                        make.right.equalTo(self.tapButtons[0].mas_left).offset(-spacing);
                    } else {
                        make.left.equalTo(self.tapButtons[0].mas_right).offset(spacing);
                    }
                } else {
                    if (isRTL) {
                        make.right.equalTo(self.tapButtons[1].mas_left).offset(-spacing);
                    } else {
                        make.left.equalTo(self.tapButtons[1].mas_right).offset(spacing);
                    }
                }
            } else if (buttonCount == 4) {
                if (i == 0) {
                    if (isRTL) {
                        make.right.equalTo(buttonContainerView.mas_right).offset(ZOOM(-10));
                    } else {
                        make.left.equalTo(buttonContainerView.mas_left).offset(ZOOM(10));
                    }
                } else if (i == 1) {
                    if (isRTL) {
                        make.right.equalTo(self.tapButtons[0].mas_left).offset(-spacing);
                    } else {
                        make.left.equalTo(self.tapButtons[0].mas_right).offset(spacing);
                    }
                } else if (i == 2) {
                    if (isRTL) {
                        make.right.equalTo(self.tapButtons[1].mas_left).offset(-spacing);
                    } else {
                        make.left.equalTo(self.tapButtons[1].mas_right).offset(spacing);
                    }
                } else {
                    if (isRTL) {
                        make.right.equalTo(self.tapButtons[2].mas_left).offset(-spacing);
                    } else {
                        make.left.equalTo(self.tapButtons[2].mas_right).offset(spacing);
                    }
                }
            }
        }];
    }
}


#pragma mark - Transition

// 作为UIViewControllerTransitioningDelegate的实现
// 弹窗出现
- (id<UIViewControllerAnimatedTransitioning>)animationControllerForPresentedController:(UIViewController *)presented presentingController:(UIViewController *)presenting sourceController:(UIViewController *)source {
    CustomTransition *transition = [[CustomTransition alloc] init];
    transition.isPresenting = YES;  // 传递弹窗出现标志
    return transition;
}
// 弹窗消散
- (id<UIViewControllerAnimatedTransitioning>)animationControllerForDismissedController:(UIViewController *)dismissed {
    CustomTransition *transition = [[CustomTransition alloc] init];
    transition.isPresenting = NO;   // 传递弹窗消失标志
    return transition;
}

#pragma mark - Lazy Loading

- (UIImageView *)imageView {
    if (!_imageView) {
        _imageView = [[UIImageView alloc] init];
    }
    return _imageView;
}

- (UIButton *)closeButton {
    if (!_closeButton) {
        _closeButton = [UIButton buttonWithType:UIButtonTypeCustom];
    }
    return _closeButton;
}


@end
