#import "DynamicPopupViewController.h"
#import "WBDynamicPopupResUnzip.h"
#import "CustomTransition.h" // 引入自定义转场动画类
#import "DynamicAnimationViewController.h"
#import "WBRouteManager.h"
#import "WBWebViewController.h"
#import "WBWebViewManager.h"

#define SKIP_DELAY 0.1

@interface DynamicPopupViewController ()

@property(nonatomic, strong)DynamicAnimationViewController *animationVC;    // 主动画
@property(nonatomic, strong)DynamicAnimationViewController *AsubAnimationVC;     // 副动画A
@property(nonatomic, strong)DynamicAnimationViewController *BsubAnimationVC;     // 副动画B
@property(nonatomic, strong)DynamicAnimationViewController *rearAnimationVC;    // 后置动画

@property (strong, nonatomic) NSDictionary *AcallbackData;  // 点击A面动画调用相应接口所返回的数据
@property (assign, nonatomic) BOOL isHandlingTappedA;   // A视图互斥点击

@end

@implementation DynamicPopupViewController

- (instancetype)initWithAmain:(NSDictionary *)Amain Bmain:(NSDictionary *)Bmain Asub:(NSDictionary *)Asub Bsub:(NSDictionary *)Bsub frontAnimation:(NSDictionary *)frontAnimation rearAnimation:(NSDictionary *)rearAnimation linkUrl:(NSString *)linkUrl richMessageLinkId:(NSString *)richMessageLinkId AnimationAtEnd:(NSDictionary *)animationAtEnd linkType:(NSString *)linkType dismiss:(NSString *)dismiss{
    self = [super initWithNibName:nil bundle:nil];
    if (self) {
        self.Amain = Amain;
        self.Bmain = Bmain;
        self.Asub = Asub;
        self.Bsub = Bsub;
        self.frontAnimation = frontAnimation;
        self.rearAnimation = rearAnimation;
        self.linkUrl = linkUrl;
        self.richMessageLinkId = richMessageLinkId;
        self.linkType = linkType;
        self.dismiss = dismiss;
        self.animationAtEnd = animationAtEnd;
        self.isHandlingTappedA = NO;

        [[NSNotificationCenter defaultCenter] addObserverForName:WBPromoReceiceErrorNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            [self dismissPopupWithCompletion:nil];
        }];
        [[NSNotificationCenter defaultCenter] addObserverForName:WBPromoReceiveSuccessNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            NSDictionary *userInfo = notification.userInfo;
            if (userInfo) {
                self.AcallbackData = userInfo[@"json"];
            }
        }];

        [self loadView];
    }
    return self;
}

- (void)dealloc {
    // 移除观察者
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

#pragma mark - UI

- (void)loadView {
    [super loadView];
    self.view.backgroundColor = [UIColor colorWithWhite:0 alpha:0.8];
    // 更新动画
    if (self.frontAnimation) {  // 前置动画存在
        [self.animationVC updateWithJson:self.frontAnimation];

        [self.animationVC playWithCompletion:^(BOOL animationFinished) {
            if (animationFinished) {    // 前置动画执行结束
                [self appearA];
            }
        }];
    } else {
        [self appearA];
    }
    if (self.Asub) {
        [self.AsubAnimationVC updateWithJson:self.Asub];
        self.AsubAnimationVC.view.hidden = YES;
    }
    if (self.Bsub) {
        [self.BsubAnimationVC updateWithJson:self.Bsub];
        self.BsubAnimationVC.view.hidden = YES;
    }

    [self setUpUI];
    [self setUpEvents];
}

- (void)setUpUI {
    // 初始化UI组件
    self.closeButton = [[UIButton alloc] init];
    self.closeButton.hidden = YES;
    [self.closeButton setBackgroundImage:[UIImage imageNamed:@"Close_icon"] forState:UIControlStateNormal];
    [self.view addSubview:self.closeButton];
    // 将 closeButton 放在最上层
    [self.view bringSubviewToFront:self.closeButton];

    [self addAllConstraints];
}

- (void)setUpEvents {
    [self.closeButton addTarget:self action:@selector(dismissPopup) forControlEvents:UIControlEventTouchUpInside];
}

- (void)addAllConstraints {
    [self.closeButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.width.height.mas_equalTo(ZOOM(30));
        if ([WBAppManager sharedManager].isRTL) {
            make.left.equalTo(self.view.mas_left).offset(ZOOM(35));
        } else {
            make.right.equalTo(self.view.mas_right).offset(ZOOM(-35));
        }
        make.top.equalTo(self.view.mas_top).offset(ZOOM(150));
    }];
}

#pragma mark - function

- (void)whichEndType:(NSString *)animationEndType {
    NSString *type = self.animationAtEnd[animationEndType];
    if ([type isEqual:@"disappear"]) {
        self.handleAnimationEndType = handleAnimationAtEnd_Disappear;
    } else if ([type isEqual:@"loop"]) {
        self.handleAnimationEndType = handleAnimationAtEnd_Loop;
    } else if ([type isEqual:@"pause"]) {
        self.handleAnimationEndType = handleAnimationAtEnd_Pause;
    } else {
        self.handleAnimationEndType = handleAnimationAtEnd_Default;     // 播放完全部暂停
    }
}

- (void)handleEndWithAnimationVC:(DynamicAnimationViewController *)animationVC withType:(NSString *)type{
    switch (self.handleAnimationEndType) {
        case handleAnimationAtEnd_Disappear:
            if ([type isEqual:@"main"]) {
                self.animationVC.view.hidden = YES;
            } else {
                [animationVC disappear];
            }
            break;
        case handleAnimationAtEnd_Loop:
            [animationVC loop];
            break;
        case handleAnimationAtEnd_Pause:
            [animationVC pause];
            break;
        default:
            break;
    }
}


- (void)appearA {
    if (self.Amain) {   // 如果A面动画的资源存在
        [self.animationVC updateWithJson:self.Amain];

        [self.animationVC playWithCompletion:^(BOOL animationFinished) {
            if (animationFinished) {
                [self whichEndType:@"A_main"];
                [self handleEndWithAnimationVC:self.animationVC withType:@"main"];

                if (self.Asub) {
                    self.AsubAnimationVC.view.hidden = NO;
                    [self whichEndType:@"A_sub"];
                    [self handleEndWithAnimationVC:self.AsubAnimationVC withType:@"sub"];
                }
                self.closeButton.hidden = NO;

                UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(TappedA:)];
                tapGesture.numberOfTapsRequired = 1;
                [self.animationVC.view addGestureRecognizer:tapGesture];
                if (self.Asub) {
                    [self.AsubAnimationVC.view addGestureRecognizer:tapGesture];
                }
            }
        }];
    } else {
        [self dismissPopupWithCompletion:nil];
    }
}

- (void)TappedA:(UITapGestureRecognizer *)gestureRecognizer {
    [[WBDynamicPopupResUnzip sharedManager] sendClickEvent];    // 点击事件上报
    if (self.isHandlingTappedA) {
        // 同一时间段，只处理最早的一个点击事件
        return;
    }
    self.isHandlingTappedA = YES;

    if([self.linkType integerValue] == linkType_Dismiss || [self.linkType integerValue] == linkType_Default) {
        [self dismissPopupWithCompletion:^{
            self.isHandlingTappedA = NO;
        }];
    } else if ([self.linkType integerValue] == linkType_UrlScheme) {
        if ([self.linkUrl hasPrefix:@"webox:///page"]) {
            __block NSURL *pageUrl = [NSURL URLWithString:self.linkUrl];
            NSString *triggerId = self.richMessageLinkId ?: nil;
            if ([pageUrl.absoluteString isEqualToString:@"webox:///page/vip"] && triggerId) {
                NSURLComponents *components = [NSURLComponents componentsWithString:pageUrl.absoluteString];
                NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new];
                NSURLQueryItem *triggerItem = [NSURLQueryItem queryItemWithName:@"triggerId" value:triggerId];
                [queryItems addObject:triggerItem];
                components.queryItems = queryItems;
                pageUrl = components.URL;
            }
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [[WBRouteManager sharedManager] performRoute:pageUrl sourceInterface:@"action/popup"];
                [self dismissPopupWithCompletion:^{
                    self.isHandlingTappedA = NO;
                }];
            });
