- (void)ifBisTapped:(UIGestureRecognizer *)gesture {    // B视图被点击
    self.BsubAnimationVC.view.hidden = NO;
    self.closeButton.hidden = YES;

    NSString *linkAfterB = nil;
    NSString *linkTypeAfterB = nil;
    NSString *dismissAfterBback = nil;
    if (self.AcallbackData) {
        linkAfterB = self.AcallbackData[@"link"]; // 点击B视图之后的跳转链接
        linkTypeAfterB = self.AcallbackData[@"type"]; // 跳转链接类型
        dismissAfterBback = self.AcallbackData[@"dismiss"];   // 点击B视图跳转后，B视图消失/恢复
    }
    if (self.rearAnimation) {   // 如果后置动画存在
        [self.rearAnimationVC updateWithJson:self.rearAnimation];

        [self.rearAnimationVC playWithCompletion:^(BOOL animationFinished) {
            if (animationFinished) {
                [self dismissPopupWithCompletion:^{
                    [self handleLinkAfterB:linkAfterB linkType:linkTypeAfterB dismiss:dismissAfterBback];
                }];
            }
        }];
    } else {
        [self dismissPopupWithCompletion:^{
            [self handleLinkAfterB:linkAfterB linkType:linkTypeAfterB dismiss:dismissAfterBback];
        }];
    }
}

- (void)handleLinkAfterB:(NSString *)link linkType:(NSString *)linkType dismiss:(NSString *)dismiss {
    // 如果点击A视图路由端口有数据返回
    if (link && linkType && dismiss) {
        if([linkType integerValue] == linkType_Dismiss) {
            NSLog(@"回调路由无处理，关闭");
        } else if([linkType integerValue] == linkType_UrlScheme) {
            __block NSURL *url = [NSURL URLWithString:link]; // 使用 __block
            NSString *triggerId = self.richMessageLinkId ?: nil;
            if ([url.absoluteString isEqualToString:@"webox:///page/vip"] && triggerId) {
                NSURLComponents *components = [NSURLComponents componentsWithString:url.absoluteString];
                NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new];
                NSURLQueryItem *triggerItem = [NSURLQueryItem queryItemWithName:@"triggerId" value:triggerId];
                [queryItems addObject:triggerItem];
                components.queryItems = queryItems;
                url = components.URL;
            }
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [[WBRouteManager sharedManager] performRoute:url sourceInterface:@"action/popup"];
            });
        } else if([linkType integerValue] == linkType_Safari) {
            [UIApplication.sharedApplication openURL:[NSURL URLWithString:link] options:@{} completionHandler:nil];
        } else if([linkType integerValue] == linkType_WebView) {
            WBWebViewManager *webVC = [[WBWebViewManager alloc] initWithURL:[NSURL URLWithString:link]];
            webVC.modalPresentationStyle = UIModalPresentationFullScreen;
            UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
            webVC.webVC.dismissBlock = ^{
                [rootVC dismissViewControllerAnimated:YES completion:nil];
            };
            [self dismissViewControllerAnimated:false completion:^{
                [rootVC presentViewController:webVC animated:true completion:nil];
                if (![dismiss integerValue]) {
                    webVC.webVC.dismissBlock = ^{
                        [rootVC presentViewController:self animated:true completion:nil];
                    };
                }
            }];
        } else {
            NSLog(@"这是一个暂时无法识别的link类型");
        }
    } else {
        return;
    }
}

