- (void)handleReferralCheckResponse:(nullable NSDictionary *)json executeRouteImmediately:(BOOL)executeRouteImmediately {
    if (![json isKindOfClass:[NSDictionary class]]) {
        return;
    }

    NSDictionary *vipInfo = json[@"vipInfoVo"];
    if ([vipInfo isKindOfClass:[NSDictionary class]]) {
        WBUserInfoHttpModel *model = [WBUserInfoHttpModel modelWithJSON:vipInfo];
        [WBSettingManager.sharedManager syncWithUserInfo:model];
    }
    PostNotificationOnMainThread(WBUpdateExpirationAlertNotification, nil);

    NSDictionary *route = json[@"route"];
    if (![route isKindOfClass:[NSDictionary class]] || [route[@"type"] integerValue] != 1) {
        return;
    }

    NSDictionary *routeData = route[@"data"];
    if (![routeData isKindOfClass:[NSDictionary class]]) {
        return;
    }

    NSString *link = routeData[@"link"];
    if (![link isKindOfClass:[NSString class]] || link.length == 0) {
        return;
    }

    NSURL *url = [NSURL URLWithString:link];
    if (!url) {
        return;
    }

    NSString *sourceInterface = @"referral/check";
    if (executeRouteImmediately) {
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [[WBRouteManager sharedManager] performRoute:url sourceInterface:sourceInterface];
        });
        return;
    }

    self.pendingRouteURL = url;
    self.pendingRouteSourceInterface = sourceInterface;
}

@property(nonatomic, assign) CFAbsoluteTime enterBackgroundTime;

@property(nonatomic, strong) UIViewController *presentingPasswdVC;

@property(nonatomic, strong) Class clazz;

@property(nonatomic, assign) BOOL isAddObserver;

@property(nonatomic, assign) BOOL shouldTriggerReferralCheckOnBecomeActive;

@property(nonatomic, assign) BOOL isReferralCheckRequestInProgress;

@end

@implementation WBAppManager

#pragma mark - singleton

+ (void)load {
    NSLog(@"load WBAppManager sharedManager");
    [WBAppManager sharedManager];
}

+ (instancetype)sharedManager {
    static WBAppManager *defaultManager = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken,^{
        defaultManager = [[self alloc] init];
    });

    return defaultManager;
}

- (void)onAppEnterForeground {
    NSLog(@"foreground");
    LogApplicationState;// 记录应用程序当前的状态信息。
    self.shouldTriggerReferralCheckOnBecomeActive = YES;
    if (!self.convertToVappVC) {
        [WBEventManager onAppEnterForeground];// 通知事件管理器应用程序已进入前台，可能触发相关的事件处理。
    } else {
        self.convertToVappVC = FALSE;
    }
    [WBKeeperManager.sharedManager onAppEnterForeground];// 通知数据保持管理器应用程序已进入前台，可能进行数据的恢复或其他操作。

    // 刷新邀请数据
    [[WBReferralManager sharedManager] refreshReferralData];

    WBVAppModel *runningVApp = [WBVAppManager sharedManager].runningVApp;// 获取当前正在运行的虚拟应用（VApp）模型。

    // 处理虚拟应用的自动锁定逻辑。
    // handle vapp autolock
    if (!self.enterBackgroundTime) return; // Never enter background.// 如果从未进入后台，则不执行后续操作。
    if (!runningVApp || !runningVApp.userInfo.password || ![WBSettingManager sharedManager].IsVIP) return;// 如果没有设置自动锁定时长或当前时间与进入后台的时间差小于自动锁定时长，则不执行后续操作。
    if (!runningVApp.autoLockDuration || CFAbsoluteTimeGetCurrent() - self.enterBackgroundTime < runningVApp.autoLockDuration) return;
    UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];   // 获取当前应用程序的根视图控制器。
    WBPasswordViewController *passwdVC = [[WBPasswordViewController alloc] init];// 初始化密码输入视图控制器。
    passwdVC.vapp = runningVApp;
    passwdVC.bioEnable = true;// 启用生物识别功能。
    passwdVC.type = WBPasswordViewControllerTypeEntry;// 设置密码输入类型为进入。
    __weak UIViewController *weakPasswdVC = passwdVC;// 使用弱引用避免内存强引用循环。
    // 设置密码输入成功的处理块，用于解散密码输入视图控制器。
    passwdVC.successBlock = ^{
        [weakPasswdVC dismissViewControllerAnimated:true completion:nil];
        self.presentingPasswdVC = nil;// 清除强引用。
    };
    // 将密码输入视图控制器封装进导航控制器，并设置全屏展示样式。
    UINavigationController *wrapVC = [[UINavigationController alloc] initWithRootViewController:passwdVC];
    wrapVC.modalPresentationStyle = UIModalPresentationFullScreen;
    // 根据是否有其他视图控制器正在展示，决定在哪个视图控制器上展示密码输入导航控制器。
    [rootVC.presentedViewController ?: rootVC presentViewController:wrapVC animated:false completion:nil];
    self.presentingPasswdVC = wrapVC;// 更新当前展示的密码输入导航控制器的引用。
}

- (void)onAppBecomeActive {
    NSLog(@"active");
    LogApplicationState;// 记录应用程序当前的状态信息。
    self.isActive = TRUE;// 更新应用程序的活跃状态为真（TRUE）。
    if ([self isBlurEffectPresented]) {// 检查是否有模糊效果视图正在展示。
        [self dismissBlurEffect];// 如果有模糊效果视图正在展示，则解散它。
    }
    [WBEventManager onAppBecomeActive];// 通知事件管理器应用程序已变得活跃，可能触发相关的事件处理
    if (vapp_is_running()) {
        return;
    }
    [WBPaymentManager.sharedManager onAppBecomeActive];// 通知支付管理器应用程序已变得活跃，可能进行支付事务的恢复或其他操作。
    [self triggerReferralCheckIfNeeded];
}

- (void)onAppResignActive {
    NSLog(@"inactive");
    self.isActive = FALSE;// 更新应用程序的活跃状态为假（FALSE）。
    WBVAppModel *runningVApp = [WBVAppManager sharedManager].runningVApp;// 获取当前正在运行的虚拟应用（VApp）模型。
    if ([WBSettingManager sharedManager].IsVIP && runningVApp != nil && runningVApp.autoLockDuration > 0) {// 检查用户是否为 VIP，并且当前运行的 VApp 是否存在且设置了自动锁定时长。
        // 如果用户是 VIP 并且设置了自动锁定时长，则展示模糊效果，提示用户应用程序即将锁定。
        [self presentBlurEffect];
    }
    // 通知事件管理器应用程序已失去活跃状态，可能触发相关的事件处理。
    [WBEventManager onAppResignActive];
    PostNotificationOnMainThread(WBUnreadFeedbacksCheckNotification, nil);
}

- (void)onAppWillTerminate {
    NSLog(@"terminating");
    [WBEventManager onAppWillTerminate];// 通知事件管理器应用程序即将终止，可能触发相关的事件处理。
//    [WBKeeperManager.sharedManager onAppWillTerminate];// 通知数据保持管理器应用程序即将终止，可能进行数据的最终保存或其他清理操作。
    [WBVAppDownloadManager.sharedManager onAppWillTerminate];// 通知虚拟应用下载管理器应用程序即将终止，可能涉及下载任务的保存或取消。
    [WBVAppResDownloadManager.sharedManager onAppWillTerminate];// 通知虚拟应用资源下载管理器应用程序即将终止，可能涉及资源下载任务的保存或取消。
}

- (void)triggerReferralCheckIfNeeded {
    if (!self.shouldTriggerReferralCheckOnBecomeActive) {
        return;
    }
    self.shouldTriggerReferralCheckOnBecomeActive = NO;

    if (self.isReferralCheckRequestInProgress) {
        return;
    }

    NSString *token = WBSettingManager.sharedManager.Token ?: @"";
    if (token.length == 0) {
        return;
    }

    if ([WBVAppManager sharedManager].runningVApp) {
        return;
    }

    self.isReferralCheckRequestInProgress = YES;
    [[WBNetworkManager defaultManager] getReferralCheckcallback:^(id  _Nullable json, NSError * _Nullable error) {
        dispatch_async(dispatch_get_main_queue(), ^{
            self.isReferralCheckRequestInProgress = NO;
            if (error) {
                NSLog(@"Foreground referral/check failed: %@", error);
                return;
            }
            [[WBReferralManager sharedManager] handleReferralCheckResponse:json executeRouteImmediately:YES];
        });
    }];
}

